# Module defining shape hierarchy with interfaces, abstract classes, and enums

# Color enum for shapes
enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

# Interface for drawable objects
interface IDrawable:
    def draw(self) -> str: ...

# Abstract base class for all shapes
@abstract
class Shape:
    color: Color

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape with color {self.color.name}"

    def __init__(self, color: Color):
        self.color = color

# Rectangle class
class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    def draw(self) -> str:
        return f"Drawing rectangle {self.width}x{self.height}"

# Circle class
class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(color)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def draw(self) -> str:
        return f"Drawing circle with radius {self.radius}"

