# Utility module with structs and helper functions

# Point struct for coordinates
struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

# Utility class for shape calculations
class ShapeUtils:
    @static
    def distance(p1: Point, p2: Point) -> float:
        dx: float = p2.x - p1.x
        dy: float = p2.y - p1.y
        return (dx * dx + dy * dy) ** 0.5

    @static
    def total_area(shapes: list[Shape]) -> float:
        total: float = 0.0
        for s in shapes:
            total += s.area()
        return total

# Factory function - must import here to avoid circular imports
def create_default_rectangle() -> Rectangle:
    # Import at function level to avoid module-level cycles if any
    return Rectangle(10.0, 5.0, Color.BLUE)
